/**
 * A live cell on the Game of Life grid, represented as [x, y] coordinates.
 * The grid is conceptually infinite; only live cells are tracked.
 */
export type Cell = [number, number];

/**
 * Computes the next generation of live cells from the current generation
 * by applying Conway's Game of Life rules (underpopulation, survival,
 * overpopulation, reproduction).
 *
 * Current behaviour (driven by tests so far): every live cell has fewer
 * than two live neighbours and therefore dies of underpopulation, so the
 * next generation is always empty.
 */
export function nextGeneration(_currentGeneration: Cell[]): Cell[] {
  return [];
}

