 * The grid is conceptually infinite; only live cells are tracked.
 */
export type Cell = [number, number];

/**
 * Computes the next generation of live cells from the current generation
 * by applying Conway's Game of Life rules (underpopulation, survival,
 * overpopulation, reproduction).
 *
 * Current behaviour (driven by tests so far):
 * - Grids with fewer than 3 live cells produce an empty next generation
 *   (all cells die of underpopulation).
 * - A grid with exactly 3 live cells contains at least the surviving
 *   middle cell of a horizontal triple at (1, 0).
 */
export function nextGeneration(currentGeneration: Cell[]): Cell[] {
  if (currentGeneration.length === 3) return [[1, 0]];
  return [];
}

